using System;using System.Linq;using System.Windows;using System.Windows.Controls;using КулинарнаяКнига.ApplicationData;using КулинарнаяКнига.AppData;
namespace КулинарнаяКнига.Pages{public partial class RegisterPage:Page{public RegisterPage(){InitializeComponent();}
private void Reg_Click(object s,RoutedEventArgs e){if(string.IsNullOrWhiteSpace(tbName.Text)||string.IsNullOrWhiteSpace(tbLogin.Text)||string.IsNullOrWhiteSpace(pb1.Password)){MessageBox.Show("Заполните обязательные поля");return;}if(AppConnect.model01.Authors.FirstOrDefault(x=>x.Login==tbLogin.Text)!=null){MessageBox.Show("Логин занят");return;}if(pb1.Password!=pb2.Password){MessageBox.Show("Пароли не совпадают");return;}if(!float.TryParse(tbStage.Text,out var st)||st<0){MessageBox.Show("Стаж некорректен");return;}if(!dpBirth.SelectedDate.HasValue||dpBirth.SelectedDate.Value>DateTime.Now.AddYears(-14)){MessageBox.Show("Возраст <14");return;}var a=new Authors{AuthorName=tbName.Text,Login=tbLogin.Text,Password=pb1.Password,ByDay=dpBirth.SelectedDate,Stoge=st,Email=tbMail.Text,Telefon=tbPhone.Text};AppConnect.model01.Authors.Add(a);try{AppConnect.model01.SaveChanges();NavigationService?.Navigate(new LoginPage());}catch(Exception ex){MessageBox.Show(ex.Message);}}}}
